import{_ as l,c as i,o as e,ag as r}from"./chunks/framework.dvv-DFtf.js";const q=JSON.parse('{"title":"功能特性","description":"","frontmatter":{},"headers":[],"relativePath":"guide/features.md","filePath":"guide/features.md"}'),t={name:"guide/features.md"};function o(n,a,h,s,u,d){return e(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="功能特性" tabindex="-1">功能特性 <a class="header-anchor" href="#功能特性" aria-label="Permalink to &quot;功能特性&quot;">​</a></h1><p>二维码生成器提供了丰富而实用的功能，让二维码生成变得简单高效。</p><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="_1-多种二维码生成方式" tabindex="-1">1. 多种二维码生成方式 <a class="header-anchor" href="#_1-多种二维码生成方式" aria-label="Permalink to &quot;1. 多种二维码生成方式&quot;">​</a></h3><h4 id="通过扩展图标生成" tabindex="-1">通过扩展图标生成 <a class="header-anchor" href="#通过扩展图标生成" aria-label="Permalink to &quot;通过扩展图标生成&quot;">​</a></h4><ul><li>点击浏览器工具栏中的扩展图标</li><li>自动生成当前页面的二维码</li><li>适用于快速分享当前浏览的网页</li></ul><h4 id="通过右键菜单生成" tabindex="-1">通过右键菜单生成 <a class="header-anchor" href="#通过右键菜单生成" aria-label="Permalink to &quot;通过右键菜单生成&quot;">​</a></h4><ul><li><strong>生成选中文本的二维码</strong>：选中任意文本，右键选择&quot;生成二维码&quot;</li><li><strong>生成链接的二维码</strong>：右键点击链接，选择&quot;生成二维码&quot;</li><li><strong>生成当前页面的二维码</strong>：在页面空白处右键，选择&quot;生成二维码&quot;</li></ul><h3 id="_2-用户友好界面" tabindex="-1">2. 用户友好界面 <a class="header-anchor" href="#_2-用户友好界面" aria-label="Permalink to &quot;2. 用户友好界面&quot;">​</a></h3><h4 id="浮动面板设计" tabindex="-1">浮动面板设计 <a class="header-anchor" href="#浮动面板设计" aria-label="Permalink to &quot;浮动面板设计&quot;">​</a></h4><ul><li>居中显示的浮动面板，不遮挡页面内容</li><li>半透明遮罩背景，突出二维码显示</li><li>响应式布局，适配不同屏幕尺寸</li></ul><h4 id="动画效果" tabindex="-1">动画效果 <a class="header-anchor" href="#动画效果" aria-label="Permalink to &quot;动画效果&quot;">​</a></h4><ul><li>平滑的打开/关闭动画</li><li>优雅的加载动画过渡</li><li>清晰的错误状态提示</li></ul><h3 id="_3-便捷操作" tabindex="-1">3. 便捷操作 <a class="header-anchor" href="#_3-便捷操作" aria-label="Permalink to &quot;3. 便捷操作&quot;">​</a></h3><h4 id="url-管理" tabindex="-1">URL 管理 <a class="header-anchor" href="#url-管理" aria-label="Permalink to &quot;URL 管理&quot;">​</a></h4><ul><li><strong>一键复制 URL</strong>：点击复制按钮快速复制当前 URL</li><li><strong>快速选择文本</strong>：点击 URL 区域可快速选择完整文本</li><li><strong>复制成功提示</strong>：复制成功后显示视觉反馈</li></ul><h4 id="二维码下载" tabindex="-1">二维码下载 <a class="header-anchor" href="#二维码下载" aria-label="Permalink to &quot;二维码下载&quot;">​</a></h4><ul><li><strong>一键下载</strong>：点击下载按钮保存二维码图片</li><li><strong>自动命名</strong>：自动生成带时间戳的文件名</li><li><strong>下载提示</strong>：下载成功后显示通知</li><li><strong>悬停显示</strong>：鼠标悬停时显示下载按钮</li></ul><h4 id="面板控制" tabindex="-1">面板控制 <a class="header-anchor" href="#面板控制" aria-label="Permalink to &quot;面板控制&quot;">​</a></h4><ul><li><strong>关闭按钮</strong>：点击关闭按钮关闭面板</li><li><strong>遮罩关闭</strong>：点击遮罩层关闭面板</li><li><strong>ESC 快捷键</strong>：按 ESC 键快速关闭</li><li><strong>自动清理</strong>：支持多次打开，自动清除旧面板</li></ul><h3 id="_4-多语言支持" tabindex="-1">4. 多语言支持 <a class="header-anchor" href="#_4-多语言支持" aria-label="Permalink to &quot;4. 多语言支持&quot;">​</a></h3><ul><li><strong>中文</strong>：完整的中文界面和提示</li><li><strong>英文</strong>：英文界面支持</li><li><strong>日文</strong>：日文界面支持</li><li><strong>自动适配</strong>：自动识别浏览器语言并切换</li></ul><h2 id="技术特性" tabindex="-1">技术特性 <a class="header-anchor" href="#技术特性" aria-label="Permalink to &quot;技术特性&quot;">​</a></h2><h3 id="高质量二维码生成" tabindex="-1">高质量二维码生成 <a class="header-anchor" href="#高质量二维码生成" aria-label="Permalink to &quot;高质量二维码生成&quot;">​</a></h3><ul><li>使用 QRCode.js 库生成高质量二维码</li><li>支持多种内容类型（URL、文本、链接）</li><li>清晰的二维码显示，易于扫描</li></ul><h3 id="性能优化" tabindex="-1">性能优化 <a class="header-anchor" href="#性能优化" aria-label="Permalink to &quot;性能优化&quot;">​</a></h3><ul><li>轻量级实现，不影响浏览器性能</li><li>快速响应，即时生成二维码</li><li>内存占用小，资源消耗低</li></ul><h3 id="安全可靠" tabindex="-1">安全可靠 <a class="header-anchor" href="#安全可靠" aria-label="Permalink to &quot;安全可靠&quot;">​</a></h3><ul><li>基于 Chrome Extension Manifest V3</li><li>遵循 Chrome 扩展安全标准</li><li>本地处理，数据不上传</li></ul><h2 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to &quot;使用场景&quot;">​</a></h2><h3 id="场景一-分享网页" tabindex="-1">场景一：分享网页 <a class="header-anchor" href="#场景一-分享网页" aria-label="Permalink to &quot;场景一：分享网页&quot;">​</a></h3><p>快速生成网页二维码，方便在移动设备上访问或分享给他人。</p><h3 id="场景二-传输文本" tabindex="-1">场景二：传输文本 <a class="header-anchor" href="#场景二-传输文本" aria-label="Permalink to &quot;场景二：传输文本&quot;">​</a></h3><p>将选中的文本生成二维码，快速传输到其他设备。</p><h3 id="场景三-链接分享" tabindex="-1">场景三：链接分享 <a class="header-anchor" href="#场景三-链接分享" aria-label="Permalink to &quot;场景三：链接分享&quot;">​</a></h3><p>为页面中的链接生成二维码，方便移动端访问。</p><h3 id="场景四-跨设备访问" tabindex="-1">场景四：跨设备访问 <a class="header-anchor" href="#场景四-跨设备访问" aria-label="Permalink to &quot;场景四：跨设备访问&quot;">​</a></h3><p>在电脑上浏览网页，生成二维码后用手机扫描访问。</p><h2 id="未来计划" tabindex="-1">未来计划 <a class="header-anchor" href="#未来计划" aria-label="Permalink to &quot;未来计划&quot;">​</a></h2><p>我们正在开发以下功能：</p><ul><li>[ ] 支持自定义二维码颜色</li><li>[ ] 支持二维码大小调整</li><li>[ ] 添加二维码预览功能</li><li>[ ] 支持更多语言</li><li>[ ] 支持二维码样式模板</li><li>[ ] 添加历史记录功能</li></ul><h2 id="反馈与建议" tabindex="-1">反馈与建议 <a class="header-anchor" href="#反馈与建议" aria-label="Permalink to &quot;反馈与建议&quot;">​</a></h2><p>如果您有任何功能建议或使用反馈，欢迎：</p><ul><li>提交 <a href="https://gitee.com/mdsfe/qrcode-extension/issues" target="_blank" rel="noreferrer">Issue</a></li><li>参与项目贡献</li><li>分享使用体验</li></ul>',44)])])}const b=l(t,[["render",o]]);export{q as __pageData,b as default};
